package com.aadil.jobtracker.security;import com.aadil.jobtracker.UserRepository.UserRepository;import com.aadil.jobtracker.entity.UserEntity;import org.springframework.security.authentication.AuthenticationManager;import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;import org.springframework.security.core.Authentication;import org.springframework.security.core.userdetails.UsernameNotFoundException;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Service;@Servicepublic class AuthenticationService {    private final UserRepository userRepository;    private final PasswordEncoder passwordEncoder;    private final AuthenticationManager authenticationManager;    private final JwtUtility jwtUtility;    public AuthenticationService(UserRepository userRepository, PasswordEncoder passwordEncoder, AuthenticationManager authenticationManager, JwtUtility jwtUtility) {        this.userRepository = userRepository;        this.passwordEncoder = passwordEncoder;        this.authenticationManager = authenticationManager;        this.jwtUtility = jwtUtility;    }    public void login (LoginRequestDTO login){        UserEntity user = userRepository.findByEmail(login.getEmail()).orElseThrow(()->new UsernameNotFoundException("Email NOT found"));        Authentication authentication=authenticationManager.authenticate(new UsernamePasswordAuthenticationToken(user.getEmail(),user.getPassword()));        if (authentication.isAuthenticated()){            jwtUtility.generateTokens(user.getEmail());        }        else {            throw new RuntimeException("Invalid Credentials");        }        boolean isMatch=passwordEncoder.matches(login.getPassword(), user.getPassword());        if (!isMatch){            throw new RuntimeException("Invalid Credentials");        }    }    public void register (RequestRegisterDTO register){        if (userRepository.existsByEmail(register.getEmail())){            throw new RuntimeException("Email Already exists");        }        String hashedPassword = passwordEncoder.encode(register.getPassword());        UserEntity user=new UserEntity();        user.setName(register.getUsername());        user.setEmail(register.getEmail());        user.setPassword(hashedPassword);        user.setRoles(UserRoles.USER.getUserRoles());        userRepository.save(user);    }}